package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

class LineItemTest {

  @Test
  void testConstructorAndGetters() throws Exception {
    String name = "TestItem";
    int quantity = 5;
    long priceInMicros = 123456789L;
    String currencyCode = "USD";

    // Use reflection to get the constructor
    Constructor<LineItem> constructor = LineItem.class.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    LineItem lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    // Verify private fields via reflection
    Field nameField = LineItem.class.getDeclaredField("name");
    nameField.setAccessible(true);
    assertEquals(name, nameField.get(lineItem));

    Field quantityField = LineItem.class.getDeclaredField("quantity");
    quantityField.setAccessible(true);
    assertEquals(quantity, quantityField.get(lineItem));

    Field priceField = LineItem.class.getDeclaredField("priceInMicros");
    priceField.setAccessible(true);
    assertEquals(priceInMicros, priceField.get(lineItem));

    Field currencyField = LineItem.class.getDeclaredField("currencyCode");
    currencyField.setAccessible(true);
    assertEquals(currencyCode, currencyField.get(lineItem));

    // Test public getter methods
    assertEquals(name, lineItem.getName());
    assertEquals(quantity, lineItem.getQuantity());
    assertEquals(priceInMicros, lineItem.getPriceInMicros());
    assertEquals(currencyCode, lineItem.getCurrencyCode());
  }

  @Test
  void testToString() {
    LineItem lineItem = new LineItem("ItemX", 2, 1000L, "EUR");
    String toStringResult = lineItem.toString();
    assertNotNull(toStringResult);
    assertTrue(toStringResult.contains("ItemX"));
    assertTrue(toStringResult.contains("2"));
    assertTrue(toStringResult.contains("1000"));
    assertTrue(toStringResult.contains("EUR"));
  }
}
